#pragma once

// Umbrella header for code generated by `@cpp.FastServer`. Generated
// `<Service>.h` / `.tcc` / `.cpp` files include only this header for the
// fast_thrift server bits — every symbol they name (adapter base, callback,
// args parser, protocol readers/writers, response helpers) reaches them
// transitively from here. Mirrors `gen/fast_client_h.h` for the client side.

#include <thrift/lib/cpp/Thrift.h>
#include <thrift/lib/cpp2/fast_thrift/thrift/server/adapter/ThriftServerAppAdapter.h>
#include <thrift/lib/cpp2/fast_thrift/thrift/server/adapter/ThriftServerAppAdapterFactory.h>
#include <thrift/lib/cpp2/fast_thrift/thrift/server/util/FastHandlerCallback.h>
#include <thrift/lib/cpp2/protocol/BinaryProtocol.h>
#include <thrift/lib/cpp2/protocol/CompactProtocol.h>

// The primary template `apache::thrift::FastServiceHandler<Service>` is
// declared in `<thrift/lib/cpp/Thrift.h>` next to `Client` and `FastClient`.
// Generated code provides a specialization for each @cpp.FastServer-annotated
// service tag type. Users implement a service handler by inheriting from
// FastServiceHandler<MyService> and overriding the per-method async_eb_*
// virtuals.
